  "title": "S3 प्रदर्शन अनुकूलन",
  "group": "S3 प्रदर्शन",
  "options": [
    {
      "text": "रैंडम/हैश प्रीफ़िक्स का उपयोग करें"
    },
    {
      "text": "तार्किक प्रीफ़िक्स का उपयोग करें; रैंडमाइज़ेशन की आवश्यकता नहीं है"
    },
    {
      "text": "हमेशा सबसे बड़े ऑब्जेक्ट्स का उपयोग करें"
    },
    {
      "text": "ऑब्जेक्ट्स की संख्या को न्यूनतम रखें"
    }
  ],
  "questionProse": [
    "उच्च रिक्वेस्ट रेट्स के लिए S3 प्रदर्शन को कैसे ऑप्टिमाइज़ करें?"
  ],
  "explanationProse": [
    "S3 प्रदर्शन टिप्स:\n  - आधुनिक S3 प्रति प्रीफ़िक्स रिक्वेस्ट रेट्स को स्वचालित रूप से स्केल करता है\n  - प्रदर्शन के लिए आपको रैंडम/हैश प्रीफ़िक्स की आवश्यकता नहीं है\n  - ऐसे लॉजिकल की नेम्स का उपयोग करें जो आपके एक्सेस पैटर्न के अनुकूल हों\n  - यदि आप बहुत हाई रिक्वेस्ट रेट्स भेजते हैं, तो 503 Slow Down रिस्पॉन्स को मॉनिटर करें\n\n  पुराने दिशानिर्देशों में हॉट पार्टिशन्स से बचने के लिए प्रीफ़िक्स को रैंडमाइज़ करने की सलाह दी जाती थी, लेकिन AWS अब इसे डिफ़ॉल्ट प्रदर्शन आवश्यकता के रूप में सुझाव नहीं देता है।\n\n  [S3 प्रदर्शन दिशानिर्देश](https://aws.amazon.com/s3/performance/)"
  ]
}
